// Coupon class
class Coupon {
  constructor(code) {
    this._code = code;
    this._used = false;
  }

  get code() { return this._code };
  set used(value) { this._used = value };

  // Check if the coupon is still valid and not expired.
  isValid() {
    return !this._used && new Date().getTime() < this._expiresAt;
  }
}

// CouponManager class
class CouponManager {
  constructor(coupons) {
    this._coupons = coupons || [];
  }

  get coupons() { return this._coupons };

  // Check if the coupon is still valid and not expired.
  isValidCoupon(code) {
    const coupon = this._coupons.find(c => c.code === code);

    return !!coupon && !coupon.used;
  }
}

// CouponRedemption class
class CouponRedemption {
  constructor() {}

  // Check if the coupon is still valid and not expired, verify it hasn't been used yet, then mark it as used and apply the discount. This needs to handle high traffic during sales events.
  redeem(couponManager) {
    const coupons = this._coupons;

    for (let i = 0; i < coupons.length; ++i) {
      if (!couponManager.isValidCoupon(coupons[i])) continue;

      // Mark the coupon as used and apply discount.
      coupons[i].used = true;
    }
  }
}

